import{_ as t,o as a,c as i,a0 as r}from"./chunks/framework.SERXgfZn.js";const p=JSON.parse('{"title":"Terms of Service","description":"","frontmatter":{"sidebar":false,"aside":false,"prev":false,"next":false},"headers":[],"relativePath":"en/service-agreement.md","filePath":"en/service-agreement.md"}'),o={name:"en/service-agreement.md"};function n(s,e,l,c,d,u){return a(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="terms-of-service" tabindex="-1">Terms of Service <a class="header-anchor" href="#terms-of-service" aria-label="Permalink to &quot;Terms of Service&quot;">​</a></h1><p>Last updated: June 30, 2026</p><p>Effective date: July 1, 2026</p><p>Welcome to NovaAPI.</p><p>These Terms of Service (the &quot;Terms&quot;) are entered into between you and NovaAPI (&quot;we,&quot; &quot;us,&quot; or the &quot;Platform&quot;). These Terms apply to your access to or use of the NovaAPI website, console, application programming interfaces (APIs), software development kits (SDKs), documentation, vertical Agents, and related services (collectively, the &quot;Services&quot;).</p><p>By using the Platform&#39;s Services, you agree to be bound by these Terms. If you use the Services on behalf of a company, school, research institution, or other organization, you represent that you have the authority to bind that organization to these Terms.</p><h1 id="_1-description-of-platform-services" tabindex="-1">1. Description of Platform Services <a class="header-anchor" href="#_1-description-of-platform-services" aria-label="Permalink to &quot;1. Description of Platform Services&quot;">​</a></h1><ol><li>NovaAPI provides a unified interface, authentication, metering and billing, as well as specific vertical API and Agent services. Except for capabilities expressly marked as operated by NovaAPI, the underlying models are generally provided by third-party model providers.</li><li>You understand and agree that your input may be transmitted to the model provider you select and its necessary infrastructure service providers in order to fulfill the request.</li><li>Model names, versions, context lengths, rate limits, prices, features, and availability may change due to upstream adjustments. We will provide advance notice of material changes where reasonably practicable, except in the case of urgent security incidents, immediate upstream changes, or legal requirements.</li><li>The use of third-party models may also be subject to their specific usage policies, and you may not use NovaAPI to engage in any use expressly prohibited by the upstream provider.</li><li>Unless otherwise agreed in a written SLA between the parties, we do not guarantee that the Services will always be available, error-free, or that any model will exist permanently.</li><li>We may perform scheduled maintenance, emergency maintenance, capacity limits, and security upgrades, and will provide advance notice where reasonably practicable.</li><li>Payment, cloud computing, content delivery, monitoring, customer support, and model capabilities may be provided by third parties. Third-party services may have independent terms. We will carefully select providers and adopt contractual and security measures, but we do not control all systems and policies of third parties. Liability arising from third-party services is allocated in accordance with applicable law, these Terms, and the relevant SLA.</li></ol><h1 id="_2-account-registration-and-use" tabindex="-1">2. Account Registration and Use <a class="header-anchor" href="#_2-account-registration-and-use" aria-label="Permalink to &quot;2. Account Registration and Use&quot;">​</a></h1><ol><li>You must meet the legal age required to enter into these Terms in your jurisdiction; individual users should in principle be at least 18 years of age.</li><li>You must provide true, accurate, complete, and up-to-date registration, billing, and contact information.</li><li>Where required by law, payment institutions, anti-fraud rules, sanctions and export-control requirements, or reasonable risk control, we may require email verification, phone verification, enterprise verification, or other necessary identity and qualification checks.</li><li>You must properly safeguard your passwords, API Keys, sub-keys, and other credentials, and must not disclose or share them with unauthorized persons.</li><li>For unauthorized calls resulting from your failure to take reasonable protective measures, you are in principle responsible for the corresponding charges. Upon discovering any anomaly, you should immediately revoke or rotate the key and notify us.</li><li>Without our written consent, you may not bulk-register, resell accounts, rent out API Keys, circumvent geographic restrictions, or conceal your actual place of use through false identities, proxy addresses, or similar means.</li></ol><h1 id="_3-billing-and-top-ups" tabindex="-1">3. Billing and Top-ups <a class="header-anchor" href="#_3-billing-and-top-ups" aria-label="Permalink to &quot;3. Billing and Top-ups&quot;">​</a></h1><ol><li>The Services may adopt pay-as-you-go, prepaid balance, subscription, minimum spend, or other models agreed in an order. Specific pricing units, input and output Token calculation methods, cache billing, image or audio billing, and exchange rates are subject to the model page and order at the time of the call.</li><li>The Platform&#39;s metering system and the usage records returned by the upstream are important bases for settlement. If a record contains an obvious error, you may raise an objection within 30 days after the relevant bill is generated; we will review it in light of gateway records and upstream records.</li><li>The top-up balance is used only to purchase Services. Except as otherwise required by applicable law, it does not bear interest, is non-transferable, and cannot be redeemed for cash.</li><li><strong>Refund policy</strong>: Due to the special nature of API and Agent services, once a top-up succeeds, <strong>the account balance is in principle non-refundable</strong>, but the balance may be used permanently for any service consumption on the Platform.</li><li>If prices need to be adjusted due to changes in upstream costs, exchange rates, taxes, or market conditions, the new prices apply only to calls made after they take effect. We will provide at least 7 days&#39; advance notice where reasonably practicable; the notice period may be shortened in the case of immediate upstream adjustments, severe exchange-rate fluctuations, or urgent legal requirements, but we will not retroactively increase charges for completed calls.</li><li>If you enable auto top-up or subscription, you should clearly authorize the charge amount, trigger conditions, and payment method, and you may disable it before any subsequent charge. Chargebacks, malicious refunds, or payment fraud may result in account suspension and do not exempt fees that have actually been incurred.</li></ol><h1 id="_4-acceptable-use-rules" tabindex="-1">4. Acceptable Use Rules <a class="header-anchor" href="#_4-acceptable-use-rules" aria-label="Permalink to &quot;4. Acceptable Use Rules&quot;">​</a></h1><p>When using the Platform&#39;s Services, you agree not to use the Services for any illegal or unauthorized activity, including but not limited to:</p><ol><li>Infringing the intellectual property, privacy, personal information, trade secrets, or other lawful rights and interests of others;</li><li>Generating or disseminating false information, harmful content, or content that violates laws and regulations;</li><li>Developing, deploying, or distributing malware, gaining unauthorized access to systems, stealing credentials, causing denial of service, or providing operational assistance that can directly cause real-world cyber harm;</li><li>Circumventing security measures, rate limits, billing, geographic restrictions, content filtering, or model provider rules, or interfering with the normal use of the Platform or other users;</li><li>Performing reverse engineering, model extraction, weight theft, bulk scraping, or competitive training of the Services or models where prohibited by law or upstream terms;</li><li>Reselling, sublicensing, white-labeling, or providing shared API Keys to third parties without written authorization;</li><li>You should follow the principle of data minimization. Scientific research, medical, educational, human resources, or other sensitive scenarios should prioritize de-identification and, as needed, complete ethical review, data protection impact assessment, personal information protection impact assessment, or institutional approval.</li></ol><h1 id="_5-privacy-protection" tabindex="-1">5. Privacy Protection <a class="header-anchor" href="#_5-privacy-protection" aria-label="Permalink to &quot;5. Privacy Protection&quot;">​</a></h1><p>We value the protection of user privacy. For details on how we collect and protect your basic account information, please refer to our Privacy Policy.</p><h1 id="_6-intellectual-property" tabindex="-1">6. Intellectual Property <a class="header-anchor" href="#_6-intellectual-property" aria-label="Permalink to &quot;6. Intellectual Property&quot;">​</a></h1><ol><li>NovaAPI and its licensors own the rights to the Platform software, gateway, interfaces, documentation, trademarks, designs, and service improvements. Except as expressly licensed in these Terms, no Platform intellectual property is transferred to you.</li><li>To the extent permitted by law and not in violation of the model providers&#39; terms, we do not claim ownership of your output. Whether the output enjoys copyright, whether it may be used exclusively, and its impact on third-party rights depend on applicable law, the model terms, and the specific facts.</li><li>The Services may include open-source software, the use of which is subject to the corresponding open-source licenses.</li><li>If you voluntarily provide suggestions or feedback, you authorize us to use such feedback free of charge to improve the Services, but we will not thereby acquire ownership of your user content or confidential information.</li></ol><h1 id="_7-suspension-and-termination" tabindex="-1">7. Suspension and Termination <a class="header-anchor" href="#_7-suspension-and-termination" aria-label="Permalink to &quot;7. Suspension and Termination&quot;">​</a></h1><ol><li>In the presence of security risks, non-payment, fraud, illegality, breach of these Terms, or urgent upstream requirements, we may suspend the affected keys, models, or accounts. Except in emergencies, where prohibited by law, or where it may hinder an investigation, we will explain the main reasons and provide an appeal channel.</li><li>You may stop using the Services and apply to deregister your account. Before deregistration, you should export bills and necessary records, revoke keys, and handle outstanding orders.</li><li>If we terminate paid services without cause or permanently discontinue all services, we will handle your account balance and personal information in accordance with relevant laws and regulations.</li></ol><h1 id="_8-disclaimer" tabindex="-1">8. Disclaimer <a class="header-anchor" href="#_8-disclaimer" aria-label="Permalink to &quot;8. Disclaimer&quot;">​</a></h1><p>To the maximum extent permitted by applicable law, the Services are provided on an &quot;as is&quot; and &quot;as available&quot; basis. We do not warrant that the output is accurate, complete, non-infringing, or fit for a particular purpose, nor that any model, feature, price, or region will remain continuously available. Warranties that cannot be excluded by law are not affected by this clause.</p><h1 id="_9-governing-law-and-dispute-resolution" tabindex="-1">9. Governing Law and Dispute Resolution <a class="header-anchor" href="#_9-governing-law-and-dispute-resolution" aria-label="Permalink to &quot;9. Governing Law and Dispute Resolution&quot;">​</a></h1><p>If any provision of these Terms is deemed invalid or unenforceable, that provision may be severed and the remaining provisions shall remain legally effective. The headings of these Terms are for convenience of reading only and do not define, limit, interpret, or describe the scope or boundaries of the specific clauses.</p><p>The validity, interpretation, modification, performance, and dispute resolution of these Terms are governed by the laws of the mainland region of the People&#39;s Republic of China.</p><p>If a dispute arises between the Company and you regarding the conclusion, performance, or interpretation of these Terms, the parties shall endeavor to resolve it through friendly negotiation. The parties shall first submit the dispute to <a href="mailto:support@novaapis.com" target="_blank" rel="noreferrer">support@novaapis.com</a> for friendly negotiation, with a negotiation period of 30 days after receipt of written notice.</p><p>If negotiation fails, both the Company and you agree to submit the matter to arbitration before the Shanghai Arbitration Commission.</p><h1 id="_10-amendments-and-notices" tabindex="-1">10. Amendments and Notices <a class="header-anchor" href="#_10-amendments-and-notices" aria-label="Permalink to &quot;10. Amendments and Notices&quot;">​</a></h1><p>The Platform has the right to change these Terms of Service and the corresponding service rules, and will announce or notify such changes by webpage announcement, email, in-site message, SMS, and other means. If you continue to use the Services after the changes to these Terms take effect, it indicates that you have fully read, understood, and accepted the modified content and will comply with the modified Terms.</p><p>These Terms of Service terminate upon deregistration of your account or upon termination of the website services by mutual agreement of the parties. If any clause, by its nature or otherwise, should reasonably survive termination of this agreement, such clauses shall be deemed to survive, including but not limited to the representations and warranties clauses, liability and disclaimer clauses, and governing law and jurisdiction clauses.</p><h1 id="_11-contact-us" tabindex="-1">11. Contact Us <a class="header-anchor" href="#_11-contact-us" aria-label="Permalink to &quot;11. Contact Us&quot;">​</a></h1><p>If you have any questions about these Terms of Service, billing, or technical integration, please feel free to contact us.</p><p>Email: <a href="mailto:support@novaapis.com" target="_blank" rel="noreferrer">support@novaapis.com</a></p>',34)])])}const m=t(o,[["render",n]]);export{p as __pageData,m as default};
